// concentratorTwoPeers builds a concentrator config with two wireguard peers,
// each carrying the given name/psk (T81, Q21 multi-peer concentrator). An
// empty name or psk string is rendered as an empty TOML value, which
// UnmarshalText/the TOML decoder leave as the unset zero value — the same as
// omitting the key entirely.
func concentratorTwoPeers(name0, psk0, name1, psk1 string) string {
	return fmt.Sprintf(`
role = "concentrator"
psk = "%s"

[[paths]]
name = "wan"
source_addr = "203.0.113.5"

[wireguard]
private_key = "%s"
listen_port = 51820
[[wireguard.peers]]
public_key = "%s"
name = "%s"
psk = "%s"
allowed_ips = ["10.0.0.2/32"]
[[wireguard.peers]]
public_key = "%s"
name = "%s"
psk = "%s"
allowed_ips = ["10.0.0.3/32"]
`, testKey(3), testKey(1), testKey(2), name0, psk0, testKey(4), name1, psk1)
}

// edgeTwoPeers builds an edge config with two wireguard peers, used only to
// exercise the Q21 concentrator-only-scope rejection (edge dials exactly one
// concentrator peer per process).
func edgeTwoPeers() string {
	return fmt.Sprintf(`
role = "edge"
psk = "%s"

[[paths]]
name = "starlink"
source_addr = "192.0.2.10"

[wireguard]
private_key = "%s"
[[wireguard.peers]]
public_key = "%s"
endpoint = "203.0.113.5:51820"
allowed_ips = ["0.0.0.0/0"]
[[wireguard.peers]]
public_key = "%s"
endpoint = "203.0.113.9:51820"
allowed_ips = ["0.0.0.0/0"]
`, testKey(3), testKey(1), testKey(2), testKey(4))
}

// TestPeerPSKValidation is the T81 acceptance table for Q21 multi-peer
// concentrator validation: with >1 peer, each peer's psk must be present and
// pairwise-distinct (equal psks defeat authenticated demux) and each peer's
// name must be present and unique; with exactly 1 peer, the top-level psk is
// the default and a per-peer psk must be absent; an edge role config is
// rejected outright with >1 peer (concentrator-only scope, Q21).
func TestPeerPSKValidation(t *testing.T) {
	cases := []struct {
		name    string
		body    string
		wantErr string // empty means Load must succeed
	}{
		{
			name:    "两peer equal per-peer psks fails",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-b", testKey(5)),
			wantErr: "pairwise distinct",
		},
		{
			name:    "两peer missing per-peer psk fails",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-b", ""),
			wantErr: "psk is required",
		},
		{
			name:    "duplicate peer names fail",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-a", testKey(6)),
			wantErr: "must be unique",
