// TestPeerPSKValidation is the T81 acceptance table for Q21 multi-peer
// concentrator validation: with >1 peer, each peer's psk must be present and
// pairwise-distinct (equal psks defeat authenticated demux) and each peer's
// name must be present and unique; with exactly 1 peer, the top-level psk is
// the default and a per-peer psk must be absent; an edge role config is
// rejected outright with >1 peer (concentrator-only scope, Q21).
func TestPeerPSKValidation(t *testing.T) {
	cases := []struct {
		name    string
		body    string
		wantErr string // empty means Load must succeed
	}{
		{
			name:    "more than one peer with equal per-peer psks fails",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-b", testKey(5)),
			wantErr: "pairwise distinct",
		},
		{
			name:    "more than one peer with a missing per-peer psk fails",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-b", ""),
			wantErr: "psk is required",
		},
		{
			name:    "duplicate peer names fail",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-a", testKey(6)),
			wantErr: "must be unique",
		},
		{
			name:    "edge role with 2 peers fails with scope-explaining message",
			body:    edgeTwoPeers(),
			wantErr: "concentrator-only",
		},
		{
			name:    "single-peer top-level-only passes",
			body:    fill(concentratorConfig),
			wantErr: "",
		},
		{
			name:    "2 peers with distinct psks and names pass",
			body:    concentratorTwoPeers("peer-a", testKey(5), "peer-b", testKey(6)),
			wantErr: "",
		},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			path := writeConfig(t, 0o600, tc.body)
			_, err := Load(path)
			if tc.wantErr == "" {
				if err != nil {
					t.Fatalf("Load: unexpected error: %v", err)
				}
				return
			}
			if err == nil {
				t.Fatalf("expected error containing %q, got nil", tc.wantErr)
			}
			if !strings.Contains(err.Error(), tc.wantErr) {
				t.Fatalf("error = %q, want substring %q", err.Error(), tc.wantErr)
			}
		})
	}
}

